parameters:
{
  "sources": {
    "countries": {
      "db": "stg",
      "table": "RestCountries_Countries",
      "business_keys": [
        "country_code_alpha3"
      ],
      "filter": {
        "where_clause": "CAST(stg_load_date AS DATE) > '{{LastRunDateTime}}' AND country_code_alpha3 IS NOT NULL"
      }
    }
  },
  "target": {
    "db": "int",
    "table": "Country_Profile",
    "business_keys": [
      "Country_Code_Alpha3"
    ],
    "write_mode": "truncate_insert"
  },
  "transformation": {
    "steps": [
      {
        "step_id": 10,
        "name": "read_countries",
        "type": "read_source",
        "config": {
          "source_name": "countries",
          "alias": "df_countries"
        }
      },
      {
        "step_id": 20,
        "name": "dedup_countries",
        "type": "deduplicate",
        "config": {
          "input_df": "df_countries",
          "alias": "df_dedup",
          "use_source_business_keys": true,
          "source_name": "countries",
          "order_by": [
            {
              "column": "stg_load_date",
              "direction": "desc"
            }
          ]
        }
      },
      {
        "step_id": 30,
        "name": "select_country_profile",
        "type": "select",
        "config": {
          "input_df": "df_dedup",
          "alias": "df_selected",
          "columns": [
            {
              "expr": "country_code_alpha2",
              "alias": "Country_Code_Alpha2"
            },
            {
              "expr": "country_code_alpha3",
              "alias": "Country_Code_Alpha3"
            },
            {
              "expr": "country_name",
              "alias": "Country_Name"
            },
            {
              "expr": "official_country_name",
              "alias": "Official_Country_Name"
            },
            {
              "expr": "region",
              "alias": "Region"
            },
            {
              "expr": "subregion",
              "alias": "Subregion"
            },
            {
              "expr": "population",
              "alias": "Population"
            },
            {
              "expr": "area_sq_km",
              "alias": "Area_Sq_Km"
            },
            {
              "expr": "capital_city",
              "alias": "Capital_City"
            },
            {
              "expr": "latitude",
              "alias": "Latitude"
            },
            {
              "expr": "longitude",
              "alias": "Longitude"
            },
            {
              "expr": "primary_timezone",
              "alias": "Primary_Timezone"
            },
            {
              "expr": "stg_load_date",
              "alias": "stg_load_date"
            },
            {
              "expr": "batch_id",
              "alias": "batch_id"
            }
          ]
        }
      },
      {
        "step_id": 40,
        "name": "add_system_fields",
        "type": "add_system_fields",
        "config": {
          "input_df": "df_selected",
          "alias": "df_with_sys"
        }
      },
      {
        "step_id": 50,
        "name": "compute_hash",
        "type": "compute_hash",
        "config": {
          "input_df": "df_with_sys",
          "alias": "df_hashed"
        }
      },
      {
        "step_id": 60,
        "name": "write_target",
        "type": "write_target",
        "config": {
          "input_df": "df_hashed"
        }
      }
    ]
  }
}
